@implements IDisposable
@inject IAddressValidator AddressValidator

@code {
    [Parameter, EditorRequired]
    public ShippingInfo Shipping { get; set; } = default!;

    [Parameter]
    public EventCallback OnNext { get; set; }

    private CancellationTokenSource? _cts;
    private bool _isValidating;
    private string? _validationError;

    private async Task ValidateAndProceed()
    {
        // Cancel any in-flight validation (e.g. user went back and clicked Next again)
        CancelPendingValidation();

        _validationError = null;

        if (string.IsNullOrWhiteSpace(Shipping.Name) ||
            string.IsNullOrWhiteSpace(Shipping.Address) ||
            string.IsNullOrWhiteSpace(Shipping.City) ||
            string.IsNullOrWhiteSpace(Shipping.ZipCode))
        {
            _validationError = "All fields are required.";
            return;
        }

        _cts = new CancellationTokenSource();
        var token = _cts.Token;
        _isValidating = true;

        try
        {
            var isValid = await AddressValidator.ValidateAddressAsync(
                Shipping.Address, Shipping.City, Shipping.ZipCode, token);

            token.ThrowIfCancellationRequested();

            if (isValid)
            {
                await OnNext.InvokeAsync();
            }
            else
            {
                _validationError = "The address could not be verified. Please check your details.";
            }
        }
        catch (OperationCanceledException)
        {
            // Validation was intentionally cancelled — nothing to do.
        }
        finally
        {
            _isValidating = false;
        }
    }

    private void CancelPendingValidation()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    public void Dispose()
    {
        CancelPendingValidation();
    }
}

<h3>Shipping Information</h3>

<div class="mb-3">
    <label>Name</label>
    <input @bind="Shipping.Name" class="form-control" placeholder="Full name" />
</div>

<div class="mb-3">
    <label>Address</label>
    <input @bind="Shipping.Address" class="form-control" placeholder="Street address" />
</div>

<div class="mb-3">
    <label>City</label>
    <input @bind="Shipping.City" class="form-control" placeholder="City" />
</div>

<div class="mb-3">
    <label>Zip Code</label>
    <input @bind="Shipping.ZipCode" class="form-control" placeholder="Zip code" />
</div>

@if (!string.IsNullOrEmpty(_validationError))
{
    <div class="alert alert-danger">@_validationError</div>
}

<button class="btn btn-primary" disabled="@_isValidating" @onclick="ValidateAndProceed">
    @if (_isValidating)
    {
        <span class="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>
        <span>Validating…</span>
    }
    else
    {
        <span>Next</span>
    }
</button>

